const XLSX = require('xlsx');
const fs = require('fs');
const path = require('path');

const cfg = $input.first()?.json || {};
const center = cfg.nombre_centro || 'Salesianos Los Boscos';
const excelPath = cfg.excel_path || '/data/diplomas/alumnos.xlsx';
const outBase = cfg.output_folder || '/data/diplomas/output';
const ciudad = cfg.ciudad || 'Logroño';
const fecha = cfg.fecha_graduacion || new Date().toLocaleDateString('es-ES', { day: 'numeric', month: 'long', year: 'numeric' });

let wb;
try { wb = XLSX.readFile(excelPath); }
catch(e) { throw new Error('No se puede leer el Excel en: ' + excelPath + '. Coloca alumnos.xlsx en data/diplomas/'); }

const ws = wb.Sheets[wb.SheetNames[0]];
const rows = XLSX.utils.sheet_to_json(ws);
if (!rows.length) throw new Error('El Excel esta vacio (primera hoja sin datos).');

const year = new Date().getFullYear();
const outDir = path.join(outBase, String(year));
fs.mkdirSync(outDir, { recursive: true });

const cssStr = '@page{size:A4 landscape;margin:15mm}*{box-sizing:border-box}body{font-family:Georgia,serif;margin:0;padding:0}.diploma{width:100%;height:calc(100vh - 30mm);border:8px double #8B6914;padding:30px 50px;text-align:center;display:flex;flex-direction:column;justify-content:space-between;background:#fffef7}.centro{font-size:13px;color:#777;letter-spacing:4px;text-transform:uppercase}.titulo{font-size:36px;color:#8B6914;font-weight:bold;letter-spacing:3px;text-transform:uppercase}.certifica{font-size:15px;color:#555;margin-bottom:4px}.alumno{font-size:30px;color:#1a1a2e;font-weight:bold;border-bottom:2px solid #8B6914;display:inline-block;padding-bottom:4px}.descripcion{font-size:14px;color:#555;margin-top:6px}.curso{font-size:19px;color:#1a1a2e;font-weight:bold}.promocion{font-size:13px;color:#777;margin-top:4px}.firmas{display:flex;justify-content:space-around}.firma{text-align:center}.linea{width:160px;border-top:1px solid #999;margin:0 auto 5px}.fn{font-size:12px;font-weight:bold;color:#333}.fc{font-size:11px;color:#777}.pie{font-size:11px;color:#999;margin-top:6px}';

function buildBody(r) {
  return `<div class='diploma'><div><div class='centro'>${center}</div><div class='titulo'>Diploma de Graduacion</div></div><div><div class='certifica'>Se certifica que</div><div class='alumno'>${r.nombre_alumno}</div><div class='descripcion'>ha completado satisfactoriamente</div><div class='curso'>${r.curso_grado}</div><div class='promocion'>Promocion ${r.promocion}</div></div><div><div class='firmas'><div class='firma'><div class='linea'></div><div class='fn'>${r.nombre_tutor}</div><div class='fc'>Tutor/a</div></div><div class='firma'><div class='linea'></div><div class='fn'>Direccion del Centro</div><div class='fc'>Director/a</div></div></div><div class='pie'>${ciudad}, ${fecha}</div></div></div>`;
}

function wrapHTML(body) {
  return `<!DOCTYPE html><html lang='es'><head><meta charset='UTF-8'><style>${cssStr}</style></head><body>${body}</body></html>`;
}

const items = [];
for (const r of rows) {
  const body = buildBody(r);
  const html = wrapHTML(body);
  const safe = (r.nombre_alumno || 'alumno').replace(/[^a-zA-Z0-9]/g, '_').replace(/_+/g, '_');
  const fname = 'diploma_' + safe + '.html';
  const fpath = path.join(outDir, fname);
  fs.writeFileSync(fpath, html, 'utf8');
  items.push({
    json: {
      nombre_alumno: r.nombre_alumno,
      curso_grado: r.curso_grado,
      nombre_tutor: r.nombre_tutor,
      email_destinatario: r.email_destinatario || '',
      promocion: String(r.promocion || ''),
      filename: fname,
      filepath: fpath,
      output_folder: outDir
    },
    binary: {
      attachment: {
        data: Buffer.from(html, 'utf8').toString('base64'),
        mimeType: 'text/html',
        fileName: fname
      }
    }
  });
}

const batchBodies = rows.map((r, i) => buildBody(r) + (i < rows.length - 1 ? `<div style='page-break-after:always'></div>` : '')).join('');
fs.writeFileSync(path.join(outDir, 'TODOS.html'), wrapHTML(batchBodies), 'utf8');

return items;

const items = $input.all();
const conEmail = items.filter(i => i.json.email_destinatario);
const outFolder = items[0]?.json?.output_folder || '/data/diplomas/output';
return [{
  json: {
    total_diplomas: items.length,
    emails_enviados: conEmail.length,
    sin_email: items.length - conEmail.length,
    carpeta_output: outFolder,
    batch_html: outFolder + '/TODOS.html',
    mensaje: items.length + ' diplomas generados. Batch en: ' + outFolder + '/TODOS.html'
  }
}];
